function update() {
    if (gameOver) return;

    // Don't move if dx and dy are both 0
    if (dx === 0 && dy === 0) {
        draw();
        return;
    }

    const head = { x: snake[0].x + dx, y: snake[0].y + dy };

    // Check wall collision
    if (head.x < 0 || head.x >= tileCount || head.y < 0 || head.y >= tileCount) {
        endGame();
        return;
    }

    // Check self collision (exclude tail when not eating food, since it will move away)
    const checkSegments = snake.slice(0, -1);
    if (checkSegments.some(segment => segment.x === head.x && segment.y === head.y)) {
        endGame();
        return;
    }

    snake.unshift(head);

    // Check food collision
    if (head.x === food.x && head.y === food.y) {
        score++;
        scoreElement.textContent = score;
        food = generateFood();
    } else {
        snake.pop();
    }

    draw();
}

