function update() {
    if (gameOver) return;

    // Don't move if dx and dy are both 0
    if (dx === 0 && dy === 0) {
        draw();
        return;
    }

    const head = { x: snake[0].x + dx, y: snake[0].y + dy };

    // Check wall collision
    if (head.x < 0 || head.x >= tileCount || head.y < 0 || head.y >= tileCount) {
        endGame();
        return;
    }

    // Check self collision
    const eatingFood = head.x === food.x && head.y === food.y;
    // If not eating food, the tail will move away so we can exclude it from check
    const segmentsToCheck = eatingFood ? snake : snake.slice(0, -1);
    if (segmentsToCheck.some(segment => segment.x === head.x && segment.y === head.y)) {
        endGame();
        return;
    }

    snake.unshift(head);

    // Check food collision
    if (eatingFood) {
        score++;
        scoreElement.textContent = score;
        food = generateFood();
    } else {
        snake.pop();
    }

    draw();
}

